'use strict';

// A deliberately expensive "stats" routine. It stands in for a real dependency
// (think a stats / crypto / parsing library) whose work dominates the CPU
// profile on the request path. Because this file lives under `node_modules/`,
// Lanterna classifies its frames as `node_modules` and attributes them to the
// `heavy-stats` package.
function summarize(samples) {
  // O(n^2) pairwise computation — burns CPU inside the dependency frame.
  let acc = 0;
  for (let i = 0; i < samples.length; i++) {
    const si = samples[i];
    for (let j = 0; j < samples.length; j++) {
      acc += Math.sqrt(Math.abs(si - samples[j])) * Math.cos(si);
    }
  }
  return acc;
}

module.exports = { summarize };
